import React, { useEffect, useState } from 'react';
import './App.css';

type Connection = {
  connect(): void;
  disconnect(): void;
};

const activeConnections = new Set<symbol>();

function createConnection(
  roomId: string,
  onStatus: (status: string) => void,
  onActiveCount: (count: number) => void
): Connection {
  let token: symbol | null = null;

  return {
    connect() {
      if (token !== null) return;
      token = Symbol(roomId);
      activeConnections.add(token);
      onStatus('Connected to ' + roomId);
      onActiveCount(activeConnections.size);
    },
    disconnect() {
      if (token === null) return;
      activeConnections.delete(token);
      token = null;
      onStatus('Disconnected');
      onActiveCount(activeConnections.size);
    }
  };
}

function ConnectionPanel({
  roomId,
  onActiveCount
}: {
  roomId: string;
  onActiveCount: (count: number) => void;
}) {
  const [status, setStatus] = useState('Disconnected');

  useEffect(() => {
    const connection = createConnection(roomId, setStatus, onActiveCount);
    connection.connect();
    return () => connection.disconnect();
  }, [roomId, onActiveCount]);

  return (
    <div className="panel">
      <div className="label connection-status">{status}</div>
      <div className="hint">
        The effect may run setup → cleanup → setup in development. Each setup owns one matching cleanup.
      </div>
    </div>
  );
}

export default function App() {
  const [mounted, setMounted] = useState(true);
  const [roomId, setRoomId] = useState('general');
  const [renderCount, setRenderCount] = useState(0);
  const [activeCount, setActiveCount] = useState(0);

  return (
    <main className="page">
      <section className="card">
        <h1 className="title">StrictMode-safe Effect Lifecycle</h1>
        <p className="subtitle">Implement repeatable setup with a symmetrical cleanup—without suppressing React’s checks.</p>

        <div className="stats">
          <div className="stat"><span className="k">Room</span><span className="v room-value">{roomId}</span></div>
          <div className="stat"><span className="k">Active connections</span><span className="v active-count">{activeCount}</span></div>
          <div className="stat"><span className="k">Unrelated renders</span><span className="v render-count">{renderCount}</span></div>
        </div>

        <div className="actions">
          <button className="btn rerender-button" onClick={() => setRenderCount((count) => count + 1)}>Re-render</button>
          <button className="btn ghost room-button" onClick={() => setRoomId((room) => room === 'general' ? 'design' : 'general')}>Switch room</button>
          <button className="btn ghost mount-button" onClick={() => setMounted((value) => !value)}>Toggle panel</button>
        </div>

        {mounted
          ? <ConnectionPanel roomId={roomId} onActiveCount={setActiveCount} />
          : <div className="panel"><div className="label connection-status">Unmounted</div></div>}

        <p className="foot">Steady state: one active connection while mounted, zero after cleanup.</p>
      </section>
    </main>
  );
}
